    print("I'm using */3 syntax.")

@crython.job(second=range(0, 60, 2))
def bla():
    print("I'm using range(0, 60, 2).")

if __name__ == '__main__':
    crython.start()
    try:
        while True:
            time.sleep(0.2)
    except KeyboardInterrupt:
